//! gemma4-attn-chunk-smoke — minimal native mirror of the wasm
//! `/split-a` handler in `apps/distributed-inference-worker/src/index.ts`
//! (handleSplitA, lines 1885-1940).
//!
//! Purpose: produce a byte-comparable native output for the same
//! Gemma4Pipeline::forward_range_attn_chunk + get_residual +
//! get_batch_xb_residual sequence the worker runs, so we can compute
//! cosine similarity between the wasm tri-split-a path and the native
//! kernel and CLOSE the F-mesh-4 numerical-parity gap. The existing
//! `gemma4-pipeline-smoke` binary runs the WHOLE pipeline (embed →
//! all-layers → lm_head) — useful for end-to-end correctness but not
//! useful for raw-residual layer-N attn-chunk parity. This binary
//! drives ONLY the same three kernel calls the /split-a worker drives,
//! at the SAME layer, with the SAME residual bytes.
//!
//! Wire format mirror:
//!   in:  Float32 residual [seq × hidden]  (same as POST body to /split-a)
//!   out: Float32 [batch_x | batch_xb] = 2 × seq × hidden floats
//!        (same byte layout as /split-a's response body)
//!
//! NEW file. Does NOT modify any kernel, any other binary, or any
//! production wire path. Pure additive parity instrument.
//!
//! Usage:
//!   cargo run --release --bin gemma4-attn-chunk-smoke -- \
//!     --knot /tmp/gemma4-31b-it.knot \
//!     --start-layer 0 \
//!     --num-layers 1 \
//!     --seq-len 1 \
//!     --input-residual /tmp/residual_nonzero_seq1.bin \
//!     --output /tmp/native-attn-chunk-out.bin
//!
//! Then compare to the wasm /split-a response with a one-shot cosine
//! script (or the existing parity-wire-roundtrip harness reading both
//! files as raw f32-LE).

use std::env;
use std::fs;
use std::time::Instant;

use distributed_inference::loader::KnotWeights;
use distributed_inference::model_gemma4::Gemma4Pipeline;

struct Args {
    knot: String,
    start_layer: usize,
    num_layers: usize,
    seq_len: usize,
    input_residual: String,
    output: String,
}

fn parse_args() -> Result<Args, String> {
    let raw: Vec<String> = env::args().collect();
    let mut knot: Option<String> = None;
    let mut start_layer: Option<usize> = None;
    let mut num_layers: Option<usize> = None;
    let mut seq_len: Option<usize> = None;
    let mut input_residual: Option<String> = None;
    let mut output: Option<String> = None;

    let mut i = 1;
    while i < raw.len() {
        let k = raw[i].as_str();
        let v = raw
            .get(i + 1)
            .ok_or_else(|| format!("flag {} expects a value", k))?;
        match k {
            "--knot" => knot = Some(v.clone()),
            "--start-layer" => {
                start_layer = Some(v.parse().map_err(|e| format!("--start-layer: {}", e))?)
            }
            "--num-layers" => {
                num_layers = Some(v.parse().map_err(|e| format!("--num-layers: {}", e))?)
            }
            "--seq-len" => seq_len = Some(v.parse().map_err(|e| format!("--seq-len: {}", e))?),
            "--input-residual" => input_residual = Some(v.clone()),
            "--output" => output = Some(v.clone()),
            other => return Err(format!("unknown flag: {}", other)),
        }
        i += 2;
    }

    Ok(Args {
        knot: knot.ok_or("missing --knot")?,
        start_layer: start_layer.ok_or("missing --start-layer")?,
        num_layers: num_layers.ok_or("missing --num-layers")?,
        seq_len: seq_len.ok_or("missing --seq-len")?,
        input_residual: input_residual.ok_or("missing --input-residual")?,
        output: output.ok_or("missing --output")?,
    })
}

fn read_f32_le(path: &str) -> Result<Vec<f32>, String> {
    let bytes = fs::read(path).map_err(|e| format!("read {}: {}", path, e))?;
    if bytes.len() % 4 != 0 {
        return Err(format!(
            "{} has {} bytes (not f32-aligned)",
            path,
            bytes.len()
        ));
    }
    let mut out = vec![0.0f32; bytes.len() / 4];
    for (i, chunk) in bytes.chunks_exact(4).enumerate() {
        out[i] = f32::from_le_bytes([chunk[0], chunk[1], chunk[2], chunk[3]]);
    }
    Ok(out)
}

fn write_f32_le(path: &str, data: &[f32]) -> Result<(), String> {
    let mut bytes = Vec::with_capacity(data.len() * 4);
    for v in data {
        bytes.extend_from_slice(&v.to_le_bytes());
    }
    fs::write(path, &bytes).map_err(|e| format!("write {}: {}", path, e))
}

fn rms(v: &[f32]) -> f32 {
    if v.is_empty() {
        return 0.0;
    }
    let s: f32 = v.iter().map(|&x| x * x).sum();
    (s / v.len() as f32).sqrt()
}

fn nan_inf(v: &[f32]) -> (usize, usize) {
    let mut nan = 0usize;
    let mut inf = 0usize;
    for &x in v {
        if x.is_nan() {
            nan += 1;
        } else if !x.is_finite() {
            inf += 1;
        }
    }
    (nan, inf)
}

fn print_summary(label: &str, v: &[f32]) {
    let lo = v.iter().cloned().fold(f32::INFINITY, f32::min);
    let hi = v.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let (nan, inf) = nan_inf(v);
    println!(
        "  {}  len={}  rms={:.6}  range=[{:.6}, {:.6}]  nan={} inf={}",
        label,
        v.len(),
        rms(v),
        lo,
        hi,
        nan,
        inf,
    );
    let head: Vec<f32> = v.iter().take(8).cloned().collect();
    println!("    first8 = {:?}", head);
}

fn main() -> Result<(), String> {
    let args = parse_args()?;
    let t0 = Instant::now();
    println!("============================================================");
    println!(" gemma4-attn-chunk-smoke");
    println!("   knot            : {}", args.knot);
    println!("   start-layer     : {}", args.start_layer);
    println!("   num-layers      : {}  (kv_num_layers)", args.num_layers);
    println!("   seq-len         : {}", args.seq_len);
    println!("   input-residual  : {}", args.input_residual);
    println!("   output          : {}", args.output);
    println!("============================================================");

    println!("[1/5] mmap knot");
    let t = Instant::now();
    let knot = KnotWeights::load(&args.knot).map_err(|e| format!("knot load: {:?}", e))?;
    println!("       ok ({} ms)", t.elapsed().as_millis());

    println!("[2/5] Gemma4Pipeline::from_knot_with_kv_range");
    let t = Instant::now();
    // Mirror the worker boot: kv_base_layer = start_layer, kv_num_layers
    // = num_layers (matches the per-station fluid-memory KV alloc the
    // tri-split / cobordism stations use). See model_gemma4.rs:142-149
    // and apps/distributed-inference-worker/src/index.ts:584-599.
    let mut pipeline = Gemma4Pipeline::from_knot_with_kv_range(
        knot,
        Some(args.start_layer),
        Some(args.num_layers),
    )?;
    let hidden = pipeline.config.hidden_dim;
    println!(
        "       ok ({} ms)  hidden_dim={}  num_layers={}",
        t.elapsed().as_millis(),
        hidden,
        pipeline.config.num_layers
    );

    println!("[3/5] read input residual");
    let residual = read_f32_le(&args.input_residual)?;
    let expected = args.seq_len * hidden;
    if residual.len() != expected {
        return Err(format!(
            "residual length {} != seq_len*hidden = {}*{} = {}",
            residual.len(),
            args.seq_len,
            hidden,
            expected,
        ));
    }
    print_summary("input.residual ", &residual);

    println!(
        "[4/5] forward_range_attn_chunk(layer={}, start_pos=0, seq_len={}, is_first=true)",
        args.start_layer, args.seq_len
    );
    let t = Instant::now();
    // Same call shape as handleSplitA (index.ts:1924) — start_pos=0,
    // is_first=true. The worker also always passes is_first=true; the
    // tri-split stations re-key tensors as blk_0_* and override
    // num_layers=1 so the kernel always sees layer index 0 in the
    // remapped space — but native runs the unremapped knot, so we pass
    // the real start_layer here.
    pipeline.forward_range_attn_chunk(
        &residual,
        args.start_layer,
        0,
        args.seq_len,
        /* is_first_layer */ true,
    )?;
    println!("       ok ({} ms)", t.elapsed().as_millis());

    println!("[5/5] get_residual + get_batch_xb_residual + write");
    let batch_x = pipeline.get_residual(args.seq_len);
    let batch_xb = pipeline.get_batch_xb_residual(args.seq_len);
    if batch_x.len() != expected || batch_xb.len() != expected {
        return Err(format!(
            "kernel returned wrong sizes: batch_x={} batch_xb={} expected={}",
            batch_x.len(),
            batch_xb.len(),
            expected
        ));
    }
    print_summary("out.batch_x    ", &batch_x);
    print_summary("out.batch_xb   ", &batch_xb);

    let mut combined = Vec::with_capacity(batch_x.len() + batch_xb.len());
    combined.extend_from_slice(&batch_x);
    combined.extend_from_slice(&batch_xb);
    write_f32_le(&args.output, &combined)?;
    println!(
        "       wrote {} ({} bytes = {} f32s)",
        args.output,
        combined.len() * 4,
        combined.len()
    );

    println!(
        "\n[done] gemma4-attn-chunk-smoke wall={} ms",
        t0.elapsed().as_millis()
    );
    Ok(())
}
